content.value:
/* Valid fields */
input:valid {
  border: 2px solid green;
  background: #e8f5e9;
}

/* Invalid fields */
input:invalid {
  border: 2px solid red;
  background: #ffebee;
}

/* Required fields */
input:required {
  border-left: 4px solid orange;
}

/* Optional fields */
input:optional {
  opacity: 0.9;
}

/* When field is focused and invalid */
input:focus:invalid {
  outline: none;
  box-shadow: 0 0 5px red;
}

/* Custom error message styling */
input:invalid + .error-message {
  display: block;
  color: red;
  font-size: 0.8em;
}
